// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    } else if (step === 2) {
      if (formData.satisfaction === 0) {
        newErrors.satisfaction = 'Please select a satisfaction rating';
      }
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNameChange = (value: string) => {
    setFormData((prev) => ({ ...prev, name: value }));
    if (errors.name) setErrors((prev) => ({ ...prev, name: '' }));
  };

  const handleEmailChange = (value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
    if (errors.email) setErrors((prev) => ({ ...prev, email: '' }));
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData((prev) => ({ ...prev, satisfaction: parseInt(value, 10) }));
    if (errors.satisfaction) setErrors((prev) => ({ ...prev, satisfaction: '' }));
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData((prev) => ({ ...prev, comments: value }));
    }
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      if (currentStep < 4) {
        setCurrentStep((prev) => prev + 1);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
      setErrors({});
    }
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  const isStep1Valid = formData.name.trim() !== '' && formData.email.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction !== 0;
  const canProceed = currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : true;

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Box>
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 4
            </Text>
          </Row>
          <Progress
            value={currentStep}
            max={4}
            size="md"
            variant="default"
            showLabel={false}
          />
        </Box>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Contact Information</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please provide your name and email address
              </Text>
              <Input
                label="Name"
                placeholder="Your full name"
                value={formData.name}
                onChange={handleNameChange}
                required
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                placeholder="your.email@example.com"
                value={formData.email}
                onChange={handleEmailChange}
                required
                error={errors.email}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Satisfaction Rating</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                How satisfied are you with our service?
              </Text>
              <RadioGroup
                label="Satisfaction Level"
                value={String(formData.satisfaction)}
                onChange={handleSatisfactionChange}
                options={satisfactionOptions}
                direction="vertical"
                error={errors.satisfaction}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Feature Interests</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Which features are you most interested in?
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Additional Comments</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please share any additional feedback or comments (optional)
              </Text>
              <TextArea
                label="Comments"
                placeholder="Tell us what you think..."
                value={formData.comments}
                onChange={handleCommentsChange}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Review Step */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Contact Information
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      <strong>Name:</strong> {formData.name}
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      <strong>Email:</strong> {formData.email}
                    </Text>
                  </Stack>
                </Box>

                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      {formData.satisfaction} - {props.satisfactionLabels[formData.satisfaction - 1]}
                    </Text>
                  </Stack>
                </Box>

                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Feature Interests
                    </Text>
                    {formData.features.length > 0 ? (
                      <Stack gap="var(--ggui-spacing-1)">
                        {formData.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))}
                      </Stack>
                    ) : (
                      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                        No features selected
                      </Text>
                    )}
                  </Stack>
                </Box>

                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Comments
                    </Text>
                    {formData.comments ? (
                      <Text variant="body" color="var(--ggui-color-onSurface)">
                        {formData.comments}
                      </Text>
                    ) : (
                      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                        No comments provided
                      </Text>
                    )}
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 4 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canProceed}
            >
              Next
            </Button>
          )}
          {currentStep === 4 && (
            <Button
              variant="primary"
              onClick={() => setCurrentStep(5)}
            >
              Review
            </Button>
          )}
          {currentStep === 5 && (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State management
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync local state with props
  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen to stream updates from other team members
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task?.id) return;

      if (action === 'delete') {
        setLocalTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (action === 'create') {
        setLocalTasks((prev) => [...prev, task]);
      } else if (action === 'move' || action === 'edit') {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, ...task } : t))
        );
      }
    }
  }, [taskChanged.latest]);

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    props.columns?.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach((task) => {
      const colId = task.column || 'todo';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [localTasks, props.columns]);

  // Calculate totals
  const totalTasks = localTasks.length;
  const completedTasks = (tasksByColumn[props.columns?.[2]?.id || 'done'] || []).length;

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setLocalTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, column: newColumn } : t
        )
      );
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: newColumn },
      });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setLocalTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, title: newTitle } : t
        )
      );
      taskUpdate({
        action: 'edit',
        taskId,
        data: { title: newTitle },
      });
      setEditingTaskId(null);
    },
    [taskUpdate]
  );

  const handleCreateTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const taskId = `task-${Date.now()}`;
      const newTask = {
        id: taskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId,
        data: { column: columnId },
      });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500)';
      case 'medium':
        return 'var(--ggui-color-warning-500)';
      case 'low':
        return 'var(--ggui-color-success-500)';
      default:
        return 'var(--ggui-color-outline)';
    }
  };

  const getPriorityBadgeVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-container)"
          borderRadius="var(--ggui-shape-radius-lg)"
          role="status"
          aria-live="polite"
          aria-label="Task summary"
        >
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Text variant="label">Total Tasks: {totalTasks}</Text>
            <Text variant="label">Completed: {completedTasks}</Text>
          </Row>
        </Box>
        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns?.map((column) => {
            const columnTasks = tasksByColumn[column.id || ''] || [];
            const isAdding = addingColumnId === column.id;

            return (
              <Box
                key={column.id}
                background="var(--ggui-color-surfaceVariant)"
                padding="var(--ggui-spacing-4)"
                borderRadius="var(--ggui-shape-radius-lg)"
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Row justify="between" align="center">
                    <Heading level={2}>{column.name}</Heading>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Task Cards */}
                  <Stack gap="var(--ggui-spacing-3)" align="stretch">
                    {columnTasks.map((task) => {
                      const isEditing = editingTaskId === task.id;
                      const initials = (task.assignee || 'A').substring(0, 2).toUpperCase();

                      return (
                        <Card
                          key={task.id}
                          padding="var(--ggui-spacing-3)"
                          shadow="sm"
                          border
                        >
                          <Stack gap="var(--ggui-spacing-2)">
                            {/* Task Title - Edit Mode */}
                            {isEditing ? (
                              <Input
                                label="Task Title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                placeholder="Enter task title"
                              />
                            ) : (
                              <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                                <Text
                                  as={Clickable}
                                  onDoubleClick={() => {
                                    setEditingTaskId(task.id || null);
                                    setEditingTitle(task.title || '');
                                  }}
                                  variant="body"
                                  weight="semibold"
                                  role="button"
                                  tabIndex={0}
                                  onKeyDown={(e) => {
                                    if (e.key === 'Enter' || e.key === ' ') {
                                      e.preventDefault();
                                      setEditingTaskId(task.id || null);
                                      setEditingTitle(task.title || '');
                                    }
                                  }}
                                >
                                  {task.title || 'Untitled Task'}
                                </Text>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onClick={() => {
                                    setEditingTaskId(task.id || null);
                                    setEditingTitle(task.title || '');
                                  }}
                                >
                                  <Icon name="pencil" size={16} />
                                </Button>
                              </Row>
                            )}

                            {/* Priority Badge */}
                            {task.priority && (
                              <Badge variant={getPriorityBadgeVariant(task.priority)} size="sm">
                                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                              </Badge>
                            )}

                            {/* Assignee & Due Date Row */}
                            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                              {task.assignee && (
                                <Avatar
                                  name={task.assignee}
                                  size="sm"
                                  shape="circle"
                                />
                              )}
                              {task.dueDate && (
                                <Text
                                  variant="caption"
                                  color="var(--ggui-color-onSurfaceVariant)"
                                >
                                  {new Date(task.dueDate).toLocaleDateString()}
                                </Text>
                              )}
                            </Row>

                            {/* Action Buttons */}
                            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                              {isEditing ? (
                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  <Button
                                    size="sm"
                                    variant="primary"
                                    onClick={() => {
                                      handleEditTask(task.id || '', editingTitle);
                                    }}
                                  >
                                    Save
                                  </Button>
                                  <Button
                                    size="sm"
                                    variant="ghost"
                                    onClick={() => setEditingTaskId(null)}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              ) : (
                                <Dropdown
                                  trigger={
                                    <Button size="sm" variant="ghost">
                                      Move
                                    </Button>
                                  }
                                  options={(props.columns || []).map((col) => ({
                                    value: col.id || '',
                                    label: col.name || 'Unknown',
                                  }))}
                                  value={task.column || 'todo'}
                                  onChange={(newColumn) => {
                                    handleMoveTask(task.id || '', newColumn);
                                  }}
                                  placement="bottom-end"
                                />
                              )}
                            </Row>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {/* Add Task Form */}
                  {isAdding ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" border>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task Title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) =>
                            setNewTaskPriority(val as 'low' | 'medium' | 'high')
                          }
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
