/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];
  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !emailValid ? 'Enter a valid email address.' : '';
  const isStep1Valid = name.trim().length > 0 && emailValid;
  const isStep2Valid = satisfaction !== '';
  const isCurrentStepValid = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;
  const progressValue = (step / 5) * 100;
  const satisfactionOptions = useMemo(
    () => safeSatisfactionLabels.map((label, index) => ({ value: String(index + 1), label })),
    [safeSatisfactionLabels]
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!isCurrentStepValid) return;
    setStep((prev) => (prev < 5 ? prev + 1 : prev));
  }, [isCurrentStepValid]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction || 0),
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {step} of 5</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" aria-label={`Survey progress: Step ${step} of 5`} />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                error={nameError}
                placeholder="Enter your full name"
                onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                error={emailError}
                placeholder="you@example.com"
                onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-3)">
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                error={!isStep2Valid ? 'Please select a rating.' : undefined}
              />
            </Stack>
          )}

          {step === 3 && (
            <FormField label="Which features are you interested in?">
              <Stack gap="var(--ggui-spacing-3)">
                {safeFeatureOptions.length === 0 && (
                  <Alert variant="info" title="No feature options">No feature options are available.</Alert>
                )}
                {safeFeatureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => toggleFeature(feature, checked)}
                  />
                ))}
              </Stack>
            </FormField>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <TextArea
                label="Additional comments"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
                helperText="Optional: share anything else you'd like us to know."
                placeholder="Type your comments here..."
              />
            </Stack>
          )}

          {step === 5 && (
            <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={5}>Final Review</Heading>
                <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                <Text>
                  <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                  {satisfaction ? safeSatisfactionLabels[Number(satisfaction) - 1] || satisfaction : '—'}
                </Text>
                <Text>
                  <Text is="span" weight="semibold">Features:</Text>{' '}
                  {features.length > 0 ? features.join(', ') : 'None selected'}
                </Text>
                <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments provided'}</Text>
              </Stack>
            </Card>
          )}

          <Divider margin="var(--ggui-spacing-2)" />

          <Row justify="between" align="center">
            <Button variant="outline" onClick={goBack} disabled={step === 1}>
              Back
            </Button>
            {step < 5 ? (
              <Button
                variant="primary"
                onClick={goNext}
                disabled={!isCurrentStepValid}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} disabled={!isStep1Valid || !isStep2Valid}>
                Submit
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

