interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board
  const [localTasks, setLocalTasks] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>([]);
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTitle, setNewTitle] = useState<string>('');
  const [newPriority, setNewPriority] = useState<string>('medium');

  const [updateError, setUpdateError] = useState<string>('');
  useEffect(() => {
    setLocalTasks((props.tasks || []).map((task, index) => ({
      ...task,
      id: task.id || `task-${index}`,
      title: task.title || 'Untitled Task',
      priority: task.priority || 'medium',
      column: task.column || 'todo',
    })));
  }, [props.tasks]);
  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) {
      return;
    }
    const streamTask = taskChanged.latest.task;
    const streamId = streamTask.id || '';

    if (taskChanged.latest.action === 'delete') {
      if (!streamId) {
        return;
      }
      setLocalTasks((prev) => prev.filter((t) => (t.id || '') !== streamId));
      return;
    }

    setLocalTasks((prev) => {
      const existingIndex = prev.findIndex((t) => (t.id || '') === streamId);
      if (existingIndex >= 0) {
        return prev.map((t) => ((t.id || '') === streamId ? { ...t, ...streamTask, id: streamId } : t));
      }
      return [...prev, { ...streamTask, id: streamId || `stream-${Date.now()}`, title: streamTask.title || 'Untitled Task', priority: streamTask.priority || 'medium', column: streamTask.column || 'todo' }];
    });
  }, [taskChanged.latest]);

  const columnOptions = useMemo(() => {
    return (props.columns || []).map((column) => ({
      value: column.id || '',
      label: column.name || 'Unnamed Column',
    }));
  }, [props.columns]);

  const priorityToBadge = useCallback((priority?: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const safeTaskUpdate = useCallback(
    (payload: ActionTaskUpdatePayload, fallbackMessage: string) => {
      try {
        taskUpdate(payload);
      } catch (error) {
        const message = error instanceof Error ? error.message : fallbackMessage;
        setUpdateError(message);
      }
    },
    [taskUpdate],
  );

  const moveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setUpdateError('');
      setLocalTasks((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, column: targetColumn } : task)));
      safeTaskUpdate({ action: 'move', taskId, data: { column: targetColumn } }, 'Failed to move task.');
    },
    [safeTaskUpdate],
  );

  const beginEdit = useCallback((taskId: string, title?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title || '');
  }, []);

  const saveEdit = useCallback(
    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      const currentTask = localTasks.find((task) => (task.id || '') === taskId);
      setUpdateError('');
      setLocalTasks((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, title: trimmed } : task)));
      safeTaskUpdate(
        {
          action: 'edit',
          taskId,
          data: {
            column: currentTask?.column || 'todo',
            title: trimmed,
            priority: currentTask?.priority || 'medium',
            assignee: currentTask?.assignee || '',
            dueDate: currentTask?.dueDate || '',
          },
        },
        'Failed to save task edit.',
      );
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, localTasks, safeTaskUpdate],
  );

  const createTask = useCallback(
    (columnId: string) => {
      const title = newTitle.trim();
      if (!title) return;
      const nextId = `task-${Date.now()}`;
      const createdTask = {
        id: nextId,
        title,
        priority: (newPriority as 'low' | 'medium' | 'high') || 'medium',
        assignee: '',
        column: columnId || 'todo',
        dueDate: '',
      };
      setUpdateError('');
      setLocalTasks((prev) => [...prev, createdTask]);
      safeTaskUpdate({ action: 'create', taskId: nextId, data: { column: columnId || 'todo', title, priority: createdTask.priority, assignee: createdTask.assignee, dueDate: createdTask.dueDate } }, 'Failed to create task.');
      setNewTitle('');
      setNewPriority('medium');
    },
    [newPriority, newTitle, safeTaskUpdate],
  );

  const [focusedTaskId, setFocusedTaskId] = useState<string>('');
  const totalTasks = localTasks.length;
  const doneColumnId = (props.columns || []).find((c) => (c.name || '').toLowerCase() === 'done')?.id || 'done';

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" border={true} shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Task Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Track and update work across all stages</Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {String(totalTasks)}</Badge>
              <Badge variant="success">Completed: {String(completedTasks)}</Badge>
            </Row>
          </Row>
        </Card>
        {updateError ? <Alert variant="error" title="Update failed">{updateError}</Alert> : null}
        {!props.columns || props.columns.length === 0 ? (
          <Alert variant="warning" title="No columns configured">
            Add at least one column to display your kanban board.
          </Alert>
        ) : (
          <Row gap="var(--ggui-spacing-4)" align="start" wrap={true}>
            {(props.columns || []).map((column) => {
              const columnId = column.id || '';
              const tasksInColumn = localTasks.filter((task) => (task.column || '') === columnId);
              return (
                <Card
                  key={columnId || `column-${column.name || 'unknown'}`}
                  padding="var(--ggui-spacing-4)"
                  border={true}
                  shadow="sm"
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={5}>{column.name || 'Unnamed Column'}</Heading>
                      <Badge variant="default">{String(tasksInColumn.length)}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-3)">
                      {tasksInColumn.length === 0 ? (
                        <Text color="var(--ggui-color-onSurfaceVariant)">No tasks in this column.</Text>
                      ) : (
                        tasksInColumn.map((task, index) => {
                          const taskId = task.id || '';
                          const isEditing = editingTaskId === taskId;
                          const isFocused = focusedTaskId ? focusedTaskId === taskId : index === 0;
                          return (
                            <Card
                              key={taskId}
                              padding="var(--ggui-spacing-3)"
                              border={true}
                              shadow="none"
                              as={Clickable}
                              onClick={() => setFocusedTaskId(taskId)}
                              onKeyDown={(event) => {
                                if (event.key === 'ArrowDown') {
                                  event.preventDefault();
                                  const nextTask = tasksInColumn[index + 1];
                                  if (nextTask?.id) {
                                    setFocusedTaskId(nextTask.id);
                                  }
                                }
                                if (event.key === 'ArrowUp') {
                                  event.preventDefault();
                                  const prevTask = tasksInColumn[index - 1];
                                  if (prevTask?.id) {
                                    setFocusedTaskId(prevTask.id);
                                  }
                                }
                                if (event.key === 'Enter' && !isEditing) {
                                  beginEdit(taskId, task.title);
                                }
                              }}
                              style={isFocused ? { outline: '2px solid var(--ggui-color-primary-600)', outlineOffset: '2px' } : undefined}
                            >
                              <Stack gap="var(--ggui-spacing-2)">
                                {isEditing ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Row justify="between" align="center">
                                    <Text weight="medium" is="span">
                                      {task.title || 'Untitled Task'}
                                    </Text>
                                    <Row gap="var(--ggui-spacing-2)">
                                      <Button variant="ghost" size="sm" onPress={() => beginEdit(taskId, task.title)}>Edit Title</Button>
                                      <Button variant="ghost" size="sm" onPress={() => beginEdit(taskId, task.title)}>Edit</Button>
                                    </Row>
                                  </Row>

                                )}

                                <Row gap="var(--ggui-spacing-2)" align="center" wrap={true}>
                                  <Badge variant={priorityToBadge(task.priority) as 'success' | 'warning' | 'error'}>
                                    {(task.priority || 'medium').toUpperCase()}
                                  </Badge>
                                  <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                                  {task.dueDate ? <Text variant="caption">Due: {task.dueDate}</Text> : <Text variant="caption">No due date</Text>}
                                </Row>

                                <Select
                                  label="Move task"
                                  value={task.column || ''}
                                  onChange={(value) => moveTask(taskId, value)}
                                  options={columnOptions}
                                />

                                {isEditing ? (
                                  <Row gap="var(--ggui-spacing-2)">
                                    <Button variant="primary" size="sm" onPress={() => saveEdit(taskId)}>Save</Button>
                                    <Button variant="ghost" size="sm" onPress={() => { setEditingTaskId(''); setEditingTitle(''); }}>Cancel</Button>
                                  </Row>
                                ) : null}
                              </Stack>
                            </Card>
                          );
                        })
                        })
                      )}
                    </Stack>

                    {addingColumnId === columnId ? (
                      <Card padding="var(--ggui-spacing-3)" border={true} shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTitle}
                            onChange={setNewTitle}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newPriority}
                            onChange={setNewPriority}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" size="sm" onPress={() => createTask(columnId)}>Create</Button>
                            <Button variant="ghost" size="sm" onPress={() => { setAddingColumnId(''); setNewTitle(''); setNewPriority('medium'); }}>Cancel</Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="outline" onPress={() => setAddingColumnId(columnId)}>Add Task</Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}
        {totalTasks === 0 ? <Alert variant="info" title="No tasks yet">Create your first task using the Add Task button in any column.</Alert> : null}
      </Stack>
    </Container>

  );
}
